+
+exports.setPadRaw = function(padId, records, callback){
+  records = JSON.parse(records);
+  
+  async.eachSeries(Object.keys(records), function(key, cb){
+    var value = records[key]
+
+    // rewrite padId
+    var oldPadId = key.split(":");
+    oldPadId[1] = padId;
