+++ b/index.js
@@ -0,0 +1,43 @@
+/**
+ * Set given `path`
+ *
+ * @param {Object} obj
+ * @param {String} path
+ * @param {Mixed} val
+ * @api public
+ */
+
+exports.set = function (obj, path, val) {
+  var segs = path.split('.');
+  var attr = segs.pop();
+  
+  for (var i = 0; i < segs.length; i++) {
+    var seg = segs[i];
+    obj[seg] = obj[seg] || {};
+    obj = obj[seg];
+  }
+  
+  obj[attr] = val;
+};
+
+/**
+ * Get given `path`
+ *
+ * @param {Object} obj
+ * @param {String} path
+ * @return {Mixed}
+ * @api public
+ */
+
+exports.get = function (obj, path) {
+  var segs = path.split('.');
+  var attr = segs.pop();
+  
+  for (var i = 0; i < segs.length; i++) {
+    var seg = segs[i];
+    if (!obj[seg]) return;
+    obj = obj[seg];
+  }
+  
+  return obj[attr];
+};
